/// <summary>
/// The <c>CustExchRateAdjSimulationDP</c> class fetches records for the
/// <c>CustExchRateAdjSimulation</c> SRSS report.
/// </summary>
[
    SRSReportParameterAttribute(classstr(CustVendExchRateAdjSimulationContract))
]
public class ETG_VendExchRateAdjSimulationDP extends SRSReportDataProviderBase
{
    ETG_VendExchRateAdjSimulationTmp eTG_VendExchRateAdjSimulationTmp;


}

Method.Source:
protected TransDate getConsideredDate()
{
    CustVendExchRateAdjSimulationContract contract = this.parmDataContract() as CustVendExchRateAdjSimulationContract;

    return contract.parmConsideredDate();
}

/// <summary>
/// Gets the data from the <c>CustExchRateAdjSimulationTmp</c> temporary table for SRS report.
/// </summary>
/// <returns>
/// The <c>CustExchRateAdjSimulationTmp</c> temporary table.
/// </returns>
[
    SRSReportDataSetAttribute(tablestr(ETG_VendExchRateAdjSimulationTmp))
, Microsoft.Dynamics.BusinessPlatform.SharedTypes.InternalUseOnlyAttribute]
public ETG_VendExchRateAdjSimulationTmp getVendExchRateAdjSimulationTmp()
{
    select eTG_VendExchRateAdjSimulationTmp;
    return eTG_VendExchRateAdjSimulationTmp;
}

protected TransDate getExchangeRateDate()
{
    CustVendExchRateAdjSimulationContract contract = this.parmDataContract() as CustVendExchRateAdjSimulationContract;

    return contract.parmDateOfRate();
}

protected CustVendExchPrinciples getRevaluationMethod()
{
    CustVendExchRateAdjSimulationContract contract = this.parmDataContract() as CustVendExchRateAdjSimulationContract;

    return contract.parmExchPrinciple();
}

/// <summary>
/// Retrieves records based on the parameters entered.
/// </summary>
public void processReport()
{
    ETG_vendExchRateAdjSimulation eTG_CustExchRateAdjSimulation;
    VendTrans  vendTrans;
    VendSettlement vendSettlement;
    super();
    while select eTG_CustExchRateAdjSimulation where 
        eTG_CustExchRateAdjSimulation.ETG_ConsiderDate == this.getConsideredDate()
        && eTG_CustExchRateAdjSimulation.ETG_DateOfRate == this.getExchangeRateDate()
        && eTG_CustExchRateAdjSimulation.ETG_CustVendExchPrinciples == this.getRevaluationMethod()
        {
        eTG_VendExchRateAdjSimulationTmp.ETG_ConsiderDate           = eTG_CustExchRateAdjSimulation.ETG_ConsiderDate;
        eTG_VendExchRateAdjSimulationTmp.ETG_DateOfRate             = eTG_CustExchRateAdjSimulation.ETG_DateOfRate;
        eTG_VendExchRateAdjSimulationTmp.ETG_CustVendExchPrinciples = eTG_CustExchRateAdjSimulation.ETG_CustVendExchPrinciples;
        eTG_VendExchRateAdjSimulationTmp.AccountNum                 = eTG_CustExchRateAdjSimulation.AccountNum ;
        eTG_VendExchRateAdjSimulationTmp.AccountName                = eTG_CustExchRateAdjSimulation.AccountName;
        eTG_VendExchRateAdjSimulationTmp.CurrencyCode               = eTG_CustExchRateAdjSimulation.CurrencyCode;
        eTG_VendExchRateAdjSimulationTmp.TransDate                  = eTG_CustExchRateAdjSimulation.TransDate;
        eTG_VendExchRateAdjSimulationTmp.AmountCur                  = eTG_CustExchRateAdjSimulation.AmountCur;
        eTG_VendExchRateAdjSimulationTmp.CurBalance                 = eTG_CustExchRateAdjSimulation.CurBalance;
        eTG_VendExchRateAdjSimulationTmp.NewBalance                 = eTG_CustExchRateAdjSimulation.NewBalance;
        eTG_VendExchRateAdjSimulationTmp.ExchangeAdj                = eTG_CustExchRateAdjSimulation.ExchangeAdj;
        eTG_VendExchRateAdjSimulationTmp.ExchangeRate               = eTG_CustExchRateAdjSimulation.ExchangeRate;
        eTG_VendExchRateAdjSimulationTmp.CurrentBalanceReporting    = eTG_CustExchRateAdjSimulation.CurrentBalanceReporting;
        eTG_VendExchRateAdjSimulationTmp.NewBalanceReporting        = eTG_CustExchRateAdjSimulation.NewBalanceReporting;
        eTG_VendExchRateAdjSimulationTmp.ExchangeAdjReporting       = eTG_CustExchRateAdjSimulation.ExchangeAdjReporting;
        eTG_VendExchRateAdjSimulationTmp.ExchangeRateReporting      = eTG_CustExchRateAdjSimulation.ExchangeRateReporting;
        eTG_VendExchRateAdjSimulationTmp.ETGFinalSimulation         = eTG_CustExchRateAdjSimulation.ETGFinalSimulation;
        eTG_VendExchRateAdjSimulationTmp.ETG_Voucher                = eTG_CustExchRateAdjSimulation.Voucher;

        select vendTrans where vendTrans.LastSettleVoucher == eTG_CustExchRateAdjSimulation.Voucher &&
                               vendTrans.Closed == eTG_CustExchRateAdjSimulation.ETG_DateOfRate &&
                               vendTrans.TransDate == eTG_CustExchRateAdjSimulation.ETG_DateOfRate;

        eTG_VendExchRateAdjSimulationTmp.ETG_Settiledvoucher        = vendTrans.LastSettleVoucher;
        eTG_VendExchRateAdjSimulationTmp.Settileddate               = vendTrans.TransDate;
        eTG_VendExchRateAdjSimulationTmp.PostingType                = eTG_CustExchRateAdjSimulation.PostingType;
        eTG_VendExchRateAdjSimulationTmp.DocumentNumber             = eTG_CustExchRateAdjSimulation.DocumentNumber;
        eTG_VendExchRateAdjSimulationTmp.DocumentDate               = eTG_CustExchRateAdjSimulation.DocumentDate;
        eTG_VendExchRateAdjSimulationTmp.InvoiceNumber              = eTG_CustExchRateAdjSimulation.InvoiceNumber;
        eTG_VendExchRateAdjSimulationTmp.LedgerAccount              = eTG_CustExchRateAdjSimulation.LedgerAccount;
        eTG_VendExchRateAdjSimulationTmp.Text                       = eTG_CustExchRateAdjSimulation.Text;
        eTG_VendExchRateAdjSimulationTmp.PostingProfile             = eTG_CustExchRateAdjSimulation.PostingProfile;
        eTG_VendExchRateAdjSimulationTmp.ETGItemFinancialdimension  = eTG_CustExchRateAdjSimulation.ETGItemFinancialdimension;

        eTG_VendExchRateAdjSimulationTmp.insert();
        }
}
